import { readFile } from "node:fs/promises";
import { execFile as execFileCb } from "node:child_process";
import { promisify } from "node:util";
import path from "node:path";

const execFile = promisify(execFileCb);

function parseArgs(argv) {
  const opts = { file: "", server: "http://127.0.0.1:3000", apply: true, entry: "" };
  for (let i = 0; i < argv.length; i += 1) {
    const a = argv[i];
    if (!a.startsWith("--") && !opts.file) {
      opts.file = a;
      continue;
    }
    if (a === "--server") {
      opts.server = argv[++i] || opts.server;
      continue;
    }
    if (a === "--entry") {
      opts.entry = argv[++i] || "";
      continue;
    }
    if (a === "--upload-only") {
      opts.apply = false;
      continue;
    }
  }
  return opts;
}

async function readJsonManifest(filePath) {
  const raw = await readFile(filePath, "utf8");
  return JSON.parse(raw);
}

async function readZipManifest(zipPath, entryHint = "") {
  let listStdout = "";
  try {
    const listed = await execFile("unzip", ["-Z1", zipPath]);
    listStdout = listed.stdout || "";
  } catch {
    throw new Error("unzip fehlt. Installiere unzip in Termux oder nutze ein JSON-Manifest.");
  }

  const files = listStdout
    .split(/\r?\n/)
    .map((x) => x.trim())
    .filter(Boolean);

  if (files.length === 0) {
    throw new Error("ZIP ist leer.");
  }

  const wanted =
    entryHint ||
    files.find((f) => /(^|\/)patches.*\.json$/i.test(f)) ||
    files.find((f) => f.toLowerCase().endsWith(".json"));

  if (!wanted) {
    throw new Error("Keine JSON-Datei im ZIP gefunden.");
  }

  const extracted = await execFile("unzip", ["-p", zipPath, wanted]);
  const text = extracted.stdout || "";
  if (!text.trim()) {
    throw new Error(`JSON aus ZIP-Eintrag ${wanted} ist leer.`);
  }

  console.log(`[Setup] ZIP-Eintrag: ${wanted}`);
  return JSON.parse(text);
}

async function loadManifest(filePath, entryHint) {
  const ext = path.extname(filePath).toLowerCase();
  if (ext === ".zip") {
    return readZipManifest(filePath, entryHint);
  }
  if (ext === ".json") {
    return readJsonManifest(filePath);
  }
  throw new Error("Nur .json oder .zip werden unterstuetzt.");
}

async function callApi(server, route, body) {
  const res = await fetch(`${server}${route}`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(body)
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) {
    throw new Error(data.error || `HTTP ${res.status}`);
  }
  return data;
}

async function main() {
  const opts = parseArgs(process.argv.slice(2));
  if (!opts.file) {
    throw new Error(
      "Nutzung: node tools/patch/import-dispatch.mjs <manifest.json|manifest.zip> [--server URL] [--entry zip.json] [--upload-only]"
    );
  }

  console.log("[Setup] Manifest laden...");
  const manifest = await loadManifest(opts.file, opts.entry);
  const count = Array.isArray(manifest?.patches) ? manifest.patches.length : 0;
  console.log(`[Setup] Manifest ok: ${count} Patch(es)`);

  console.log("[Setup] Upload an Patch-Server...");
  await callApi(opts.server, "/api/upload-manifest", { manifest });
  console.log("[Setup] Upload abgeschlossen.");

  if (!opts.apply) {
    console.log("[Setup] Upload-only aktiv. Kein Start ausgefuehrt.");
    return;
  }

  console.log("[Setup] Patchlauf starten...");
  await callApi(opts.server, "/api/start-patches", {
    options: {
      verifyAfterEach: true,
      compareChecksums: true,
      autoRefreshGame: true
    }
  });
  console.log("[Setup] Gestartet. Live-Fortschritt im Browser unter patchUI.html sichtbar.");
}

main().catch((error) => {
  console.error(`[Fehler] ${error.message}`);
  process.exit(1);
});
